mapper.insert:
INSERT INTO GACHA_SERIES (
       id
     , title
     , manufacturer
     , price
     , view_count
     , file_id
     , released_at
     , created_at
     , updated_at
)
VALUES (
       #{id}
     , #{title}
     , #{manufacturer}
     , #{price}
     , #{viewCount}
     , #{fileId}
     , #{releasedAt}
     , #{createdAt}
     , #{updatedAt}
)

INSERT INTO GACHA_ITEM (
       series_id
     , name
     , created_at
)
VALUES (
       #{seriesId}
     , #{name}
     , #{createdAt}
)

mapper.select:
SELECT COUNT(id) FROM GACHA_SERIES
WHERE 1 = 1


        AND (
             title LIKE #{keywordPattern}
          OR manufacturer LIKE #{keywordPattern}
        )

SELECT S.id AS seriesId , S.title , S.manufacturer , S.file_id , F.file_url , S.price , S.view_count , S.released_at , S.created_at , S.updated_at FROM GACHA_SERIES S LEFT JOIN IMAGE_FILE F ON F.file_id = S.file_id WHERE 1 = 1
AND ( S.title LIKE #{keywordPattern} OR S.manufacturer LIKE #{keywordPattern} )
ORDER BY S.created_at DESC LIMIT #{pageSize} OFFSET #{offset}
